fn generate_map(arr: Array(Int64)) -> Hash(Int64, Int64) {
    # Map: XOR_sum -> Minimum_size_to_achieve_this_sum
    map = Hash(Int64, Int64)
    map[0] = 0

    for x in arr {
        updates = Hash(Int64, Int64)

        # Iterate over existing entries in the map
        for (xor, size) in map {
            # Calculate the new state achieved by including x
            new_xor = xor ^ x
            new_size = size + 1

            # Check if this new state is better (smaller size) than what is currently stored
            current_size = map[new_xor]

            # We must also check against updates, as another path might have updated it already in this iteration
            existing_updates_size = updates[new_xor]

            min_size = new_size
            if current_size != nil {
                min_size = min(min_size, current_size)
            }
            if existing_updates_size != nil {
                min_size = min(min_size, existing_updates_size)
            }

            # Store the best size found for (new_xor) so far in the updates hash
            updates[new_xor] = min(updates[new_xor] ?? 0, min_size)
        }

        # Merge updates into the main map, ensuring we only keep the minimum size
        for (xor, size) in updates {
            current_size = map[xor]
            if current_size == nil || size < current_size {
                map[xor] = size
            }
        }
    }
    return map
}

def solve(nums : Array(Int64), target : Int64) : Int64 {
    n = nums.len

    # Split the array into two halves
    n_a = n / 2
    a = nums[0..n_a - 1]
    b = nums[n_a..n - 1]

    # Generate XOR sum maps for both halves
    map_a = generate_map(a)
    map_b = generate_map(b)

    max_size = -1

    # Combine results
    for (xor_a, size_a) in map_a {
        # We need xor_b such that xor_a ^ xor_b = target
        # This means xor_b = target ^ xor_a
        required_xor_b = target ^ xor_a

